local function campfirefire(inst) inst.dycparticlefire = inst:SpawnChild( "dyc_p_fire" ) inst.dycparticlesmoke = inst:SpawnChild( "dyc_p_fire_smoke" ) inst.dycparticlespark = inst:SpawnChild( "dyc_p_fire_spark" ) if inst.components.firefx and inst.components.firefx.SetLevel then local oldFn = inst.components.firefx.SetLevel inst.components.firefx.SetLevel = function(firefx, lev, immediate, ...) inst.dycparticlefire:SetPercentage(lev * 0.2 + 0.2) inst.dycparticlesmoke:SetPercentage(lev * 0.2 + 0.2) inst.dycparticlespark:SetPercentage(lev * 0.2 + 0.2) local oldRV = oldFn(firefx, lev, immediate, ...) if inst.AnimState then inst.AnimState:Pause() inst.AnimState:SetMultColour(0x0, 0x0, 0x0, 0x0) end return oldRV end end end return campfirefire 